package pkg

import (
	"fmt"
	"strings"
)

func SumAndFormat(values []int, label string, includeDetails bool) (int, string, error) {
	sum := computeSum(values)
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	details := ""
	if includeDetails {
		details = buildDetails(values)
	}
	if label != "" {
		details = label + ": " + details
	}
	return sum, details, nil
}

func computeSum(values []int) int {
	var sum int
	for _, v := range values {
		if v > 0 { sum += v } else if v < 0 { sum -= v }
	}
	return sum
}

func buildDetails(values []int) string {
	var b strings.Builder
	for _, v := range values {
		if v > 0 { b.WriteString(fmt.Sprintf("%d,", v)) } else if v < 0 { b.WriteString(fmt.Sprintf("(%d),", v)) }
	}
	return b.String()
}

func SumAndFormat(numbers []int, label string, includeDetails bool) (int, string, error) {
	sum, details := computeSumAndDetails(numbers, includeDetails)
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if label != "" {
		details = label + ": " + details
	}
	return sum, details, nil
}

func computeSumAndDetails(numbers []int, includeDetails bool) (int, string) {
	var sum int
	var sb strings.Builder
	for _, n := range numbers {
		if n > 0 {
			sum += n
			if includeDetails { sb.WriteString(fmt.Sprintf("%d,", n)) }
		} else if n < 0 {
			sum -= n
			if includeDetails { sb.WriteString(fmt.Sprintf("(%d),", n)) }
		}
	}
	return sum, sb.String()
}

func d(a []int, b string, c bool) (int, string, error) {
	var r int
	var s strings.Builder
	for _, v := range a {
		if v > 0 { r += v; if c { s.WriteString(fmt.Sprintf("%d,", v)) } } else if v < 0 { r -= v; if c { s.WriteString(fmt.Sprintf("(%d),", v)) } }
	}
	if r == 0 { return 0, "", fmt.Errorf("empty result for %s", b) }
	var out string
	if b != "" { out = b + ": " + s.String() } else { out = s.String() }
	return r, out, nil
}
